local PlayerDataCache = {}

SumRechargeHelper = {}

---获取玩家的充值金额
local function getPlayerRechargeAmount(userId, func)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    WebService:GetSumRechargeGCube(userId, function(gcube)
        if not gcube then
            return
        end
        if not player:checkReady() then
            return
        end
        if func then
            func(gcube)
        end
        PacketSender:sendLuaCommonData(player.rakssid, "SumRechargeGCube", gcube)
    end)
end

local function savePlayerData(userId)
    local cache = PlayerDataCache[tostring(userId)]
    if not cache then
        return
    end
    DBManager:savePlayerData(userId, "SumRecharge", cache, true)
end

local function onPlayerReceive(player)
    local cache = PlayerDataCache[tostring(player.userId)]
    if not cache then
        return
    end
    local current = SumRechargeConfig:getSumRecharge(cache.currentId)
    if not current then
        return
    end

    if not ReceiveSumRechargeStartEvent:invoke(player, current.Rewards) then
        return
    end

    getPlayerRechargeAmount(player.userId, function(gcube)
        if cache.currentId ~= current.Id then
            return
        end
        if gcube >= current.GCube then
            for _, reward in pairs(current.Rewards) do
                ReceiveSumRechargeEvent:invoke(player, reward.Type, reward.RewardId, reward.Count, reward.Meta)
            end
            ReceiveSumRechargeEndEvent:invoke(player, cache.currentId)
            local data = DataBuilder.new():addParam("Id", cache.currentId):getData()
            PacketSender:sendLuaCommonData(player.rakssid, "SumRechargeResult", data)
            cache.currentId = current.NextId
            cache.remindDay = 0
            local builder = DataBuilder.new():addParam("Id", cache.currentId)
            PacketSender:sendLuaCommonData(player.rakssid, "ShowSumRecharge", builder:getData())
        end
    end)
end

function SumRechargeHelper:init()
    CommonDataEvents:registerCallBack("SumRechargeReceive", function(userId, data)
        local player = PlayerManager:getPlayerByUserId(userId)
        if not player then
            return
        end
        onPlayerReceive(player)
    end)
    RechargeResultEvent.registerCallBack(function(rakssid, type, result)
        if type ~= 1 then
            ---不是购买金魔方
            return
        end
        if result ~= 1 then
            ---购买不成功
            return
        end
        local player = PlayerManager:getPlayerByRakssid(rakssid)
        if not player then
            return
        end
        local config = SumRechargeConfig:getMinGCubeConfig(player:getSex())
        if not config then
            return ---没有充值活动
        end
        local cache = PlayerDataCache[tostring(player.userId)]
        if not cache then
            return
        end
        if SumRechargeConfig:getSumRecharge(cache.currentId) then
            getPlayerRechargeAmount(player.userId)
        end
    end)
end

function SumRechargeHelper:onPlayerReady(player)
    local config = SumRechargeConfig:getMinGCubeConfig(player:getSex())
    if not config then
        return ---没有充值活动
    end
    DBManager:getPlayerData(player.userId, "SumRecharge", function(userId, subKey, data)
        if not player:checkReady() then
            return
        end

        if not DBManager:isAutoCache() then
            DBManager:addCache(userId, subKey, data)
        end

        local cache = { remindDay = 0, currentId = config.Id }
        if not data.__first then
            cache.remindDay = data.remindDay or 0
            cache.currentId = data.currentId or config.Id
        end
        PlayerDataCache[tostring(player.userId)] = cache
        ---发送数据给玩家，玩家显示首充信息
        local dayKey = DateUtil.getYearDay()
        local builder = DataBuilder.new():addParam("Id", cache.currentId)
        if dayKey ~= cache.remindDay and config.DailyRemind then
            builder:addParam("Remind", true)
            ---需要每日提醒
            cache.remindDay = dayKey
        end
        PacketSender:sendLuaCommonData(player.rakssid, "ShowSumRecharge", builder:getData())
        if SumRechargeConfig:getSumRecharge(cache.currentId) then
            getPlayerRechargeAmount(userId)
        end
    end)
end

function SumRechargeHelper:trySaveSumRechargeData(ticks)
    if ticks % 60 ~= 0 then
        return
    end
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        savePlayerData(player.userId)
    end
end

function SumRechargeHelper:onPlayerLogout(userId)
    savePlayerData(userId)
    PlayerDataCache[tostring(userId)] = nil
end

function SumRechargeHelper:removeCache(player)
    if not DBManager:isAutoCache() then
        DBManager:removeCache(player.userId, { "SumRecharge" })
    end
end

function SumRechargeHelper:resetSumRecharge(player)
    if not player:checkReady() then
        return
    end
    local config = SumRechargeConfig:getMinGCubeConfig(player:getSex())
    if not config then
        return ---没有充值活动
    end
    local cache = PlayerDataCache[tostring(player.userId)]
    if not cache then
        LuaTimer:schedule(function()
            SumRechargeHelper:resetSumRecharge(player)
        end, 1000)
        return
    end
    cache = { remindDay = 0, currentId = config.Id }
    PlayerDataCache[tostring(player.userId)] = cache
    ---发送数据给玩家，玩家显示首充信息
    local dayKey = DateUtil.getYearDay()
    local builder = DataBuilder.new():addParam("Id", cache.currentId)
    if dayKey ~= cache.remindDay and config.DailyRemind then
        builder:addParam("Remind", true)
        ---需要每日提醒
        cache.remindDay = dayKey
    end
    PacketSender:sendLuaCommonData(player.rakssid, "ShowSumRecharge", builder:getData())
    getPlayerRechargeAmount(player.userId)
end